#!/bin/bash
# SubagentStop hook: Auto-extracts learnings from agent transcripts.
# Generated by buddyx-forge.

INPUT=$(cat)
if ! command -v jq &>/dev/null; then
  exit 0
fi
AGENT_TYPE=$(echo "$INPUT" | jq -r '.agent_type // empty' 2>/dev/null)
AGENT_TYPE=$(echo "$AGENT_TYPE" | tr -cd 'a-zA-Z0-9-')
LAST_MESSAGE=$(echo "$INPUT" | jq -r '.last_assistant_message // empty' 2>/dev/null)
PROJECT_DIR="$(git rev-parse --show-toplevel 2>/dev/null || pwd)"

if ! echo "$AGENT_TYPE" | grep -q "^webapp-"; then
  exit 0
fi

if [ -z "$LAST_MESSAGE" ] || [ "$LAST_MESSAGE" = "null" ]; then exit 0; fi

QUEUE_FILE="${PROJECT_DIR}/.claude/agent-memory/learning-queue.md"
SHARED_FILE="${PROJECT_DIR}/.claude/agent-memory/shared-learnings.md"
TODAY=$(date +%Y-%m-%d)

# Skip if agent already wrote to shared-learnings
SHARED_MODIFIED=$(git -C "$PROJECT_DIR" diff --name-only 2>/dev/null | grep "shared-learnings.md" || true)
if [ -n "$SHARED_MODIFIED" ]; then
  exit 0
fi

KEYWORDS="discovered|found that|turns out|gotcha|important:|note:|pattern:|learned that|realized|watch out|be careful|must always|never do|always use"
MATCHES=$(echo "$LAST_MESSAGE" | grep -iE "$KEYWORDS" | head -5)

[ -z "$MATCHES" ] && exit 0

if [ ! -f "$QUEUE_FILE" ]; then
  cat > "$QUEUE_FILE" <<'QEOF'
# Learning Queue

> Auto-captured from agent transcripts. Review periodically.
> Move useful entries to shared-learnings.md as [NEW 0/3].

QEOF
fi

{
  echo ""
  echo "### [${TODAY}] ${AGENT_TYPE}"
  echo "$MATCHES" | while IFS= read -r line; do
    [ -n "$line" ] && echo "- ${line}"
  done
} >> "$QUEUE_FILE"

# Keep queue under 100 lines
QUEUE_LINES=$(wc -l < "$QUEUE_FILE" 2>/dev/null || echo "0")
if [ "$QUEUE_LINES" -gt 100 ]; then
  head -6 "$QUEUE_FILE" > "${QUEUE_FILE}.tmp"
  tail -80 "$QUEUE_FILE" >> "${QUEUE_FILE}.tmp"
  mv "${QUEUE_FILE}.tmp" "$QUEUE_FILE"
fi

exit 0
